var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"가져왔습니다. 이사장님.","JPN":"お持ちしました、理事長。","ENG":"Here you are, Ms. Chairwoman.","TWN":"帶來了，理事長。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아 고마워요 루시드 선생님.","JPN":"ありがとうございます、ルシード先生。","ENG":"Oh, thank you, Ms. Lucid.","TWN":"謝謝你，露西德老師。"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그런데 나이엘 양의 자작 소설은 갑자기 왜…….","JPN":"ところで、ナイエルさんの自作小説はなぜ……","ENG":"But why did you want Naielle's novel, all of a sudden...?","TWN":"可是，為什麼突然提到奈爾的自創小說……"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아하하, 그게…… 세상을 구하는데 이게 꼭 필요하거든요.","JPN":"あはは、それが……世界を救うために、これがどうしても必要なんです。","ENG":"Ah ha ha, well... we need this to save the world.","TWN":"哈哈哈，這個……拯救世界的時候，這個是必需的。"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"네……?","JPN":"え……？","ENG":"Excuse me...?","TWN":"嗯……？"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"흠흠……!","JPN":"ごほん……！","ENG":"Ahem...!","TWN":"咳咳……！"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"그럼, 읽을게.","JPN":"じゃあ、読むわね。","ENG":"Then, I'll start reading it.","TWN":"那我就讀了喔。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아득한 고대로부터 이어져 온 의지가 내 영혼에 흐르고 있었다.","JPN":"遥か古代から受け継がれてきた意志が私の魂に流れている。","ENG":"Their wills, passed down from the start of time, flow in my soul.","TWN":"傳承於遙遠古代的意志在我的靈魂中流淌。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"모든 우주의 힘과…….","JPN":"全宇宙の力と……","ENG":"With the power of the entire universe...","TWN":"所有宇宙的力量……"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"우와아아아아악!!!!!","JPN":"わああああああっ！！","ENG":"AAAAAAAGH!!!","TWN":"嗚哇啊啊啊啊啊啊啊！！！"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"지금 이게 뭐 하자는 거야?! 그건 또 어디서 났어!","JPN":"な、何してるのよ！！　それ、どこで手に入れたの！？","ENG":"What are you doing?! Where did you get that?!","TWN":"現在這是幹什麼？！那又是從哪弄來的！"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"나이엘 학생. 방금 이사장님께 모든 사정을 전해 들었어요.","JPN":"ナイエルさん。先ほど理事長にすべて聞きました。","ENG":"Naielle. The Chairwoman just told me what's going on.","TWN":"奈爾同學，剛剛聽理事長說了所有情況。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"봉사하실 때 아인과 츠바이에게 책 많이 읽어 주셨죠?","JPN":"ボランティアをしていた時、アインとツヴァイに本をたくさん読んであげましたよね。","ENG":"You used to read a lot of books to Eins and Zwei as volunteer work, correct?","TWN":"你在做志工服務時，經常給艾茵和茨粨讀故事書，對吧？"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아이들이 가장 좋아하던 게 바로 그 책이었거든요.","JPN":"子どもたちがいちばん好きな本がこれだったんです。","ENG":"The children loved that book the most.","TWN":"孩子們最喜歡的就是那本書。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"나이엘 언니다! 언니~!!","JPN":"ナイエルお姉ちゃんだ！　お姉ちゃん～！！","ENG":"It's Naielle! Hi, Naielle!","TWN":"奈爾姊姊！姊姊～！！"},"stage":{"bg":"DATABASE_02","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"와~ 언니가 전설의 기사랑 싸우려나 봐!","JPN":"わあ～お姉ちゃん、伝説の騎士と戦うのかな？","ENG":"Wow! I think Naielle is going to fight the legendary knight!","TWN":"哇～姊姊好像要和傳說中的騎士戰鬥了！"},"stage":{"bg":"DATABASE_02","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"응원하고 있어요 학생. 부디 모두를 위해 세상을 구해주세요.","JPN":"応援していますよ。どうか、皆のために世界を救ってください。","ENG":"The students are cheering for you. Please, save the world for everyone.","TWN":"同學，我支持你，請為了大家拯救這個世界吧。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아니 아니 잠깐!! 나 지금 상황이 하나도 이해 안 되거든?!","JPN":"ちょっとちょっと！！　この状況まったく意味がわからないんだけど！？","ENG":"Hey, w-wait!! I don't understand what's going on right now!","TWN":"喂喂，等等！！我現在完全搞不清楚狀況？！"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"와 이리 부끄러워하는데? 애들 앞에선 잘 읽었다매?","JPN":"今さら何恥ずかしがっとんねん？　子どもたちの前ではすらすら読んでたんやろ？","ENG":"What are ya so embarrassed 'bout? Didn't ya read it out loud to the children?","TWN":"哇，怎麼這麼害羞？不是在孩子們面前讀得很好嗎？"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아니 그건 애들이니까 그렇지, 대중들한텐 무리라고!","JPN":"いや、それは子どもの前だからできたわけで、こんな大勢の前では無理よ！！","ENG":"That's because they were kids! It's embarrassing to read it to the public!","TWN":"那是因為他們是孩子，對別人我做不到！"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"할 거야……. 생중계.","JPN":"やるよ……生中継。","ENG":"There will be... a livestream.","TWN":"要做的……現場直播。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"전 세계 사람들에게…… 나이엘의 모습.","JPN":"全世界に見せる……ナイエルの姿。","ENG":"A livestream of Naielle... to everyone in the world.","TWN":"向全世界的人們展示……奈爾的樣子。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"미리네! 설마 이게 당신이 말한 작전이야?!","JPN":"マリ！　まさかあんたが言ってた作戦ってこれ！？","ENG":"Mi Rinae! Is this the plan you told me about?!","TWN":"宓璃奈！難道這就是你說的作戰計畫？！"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그래. 사람들의 무의식적인 CRF의 발현을 역으로 이용하는 기다.","JPN":"そうや。人々の無意識的なCRFの発現を逆利用するんや。","ENG":"Yup. We're gonna take advantage of the others' subconscious manifestation of CRF.","TWN":"對，就是要反過來利用人們無意識的CRF顯現。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};